import java.util.HashMap;
import java.util.Map;

public class Solution {
    /**
     * Generates a map containing all possible XOR sums achievable by subsets of the given array segment,
     * mapping each XOR sum to the minimum size of the subset that achieves it.
     *
     * @param nums The array segment.
     * @return A map: XOR_Sum -> Minimum_Size
     */
    private static Map<Long, Integer> generateXorSumMap(long[] nums) {
        Map<Long, Integer> map = new HashMap<>();
        int n = nums.length;

        // Iterate through all 2^n subsets using bitmasks
        for (int i = 0; i < (1 << n); i++) {
            long currentXorSum = 0;
            int currentSize = 0;

            for (int j = 0; j < n; j++) {
                // If the j-th bit is set in i, include nums[j] in the subset
                if (((i >> j) & 1) == 1) {
                    currentXorSum ^= nums[j];
                    currentSize++;
                }
            }

            // Update the map: store the minimum size for this XOR sum
            map.put(currentXorSum, Math.min(map.getOrDefault(currentXorSum, Integer.MAX_VALUE), currentSize));
        }
        return map;
    }

    public static long solve(long[] nums, long target) {
        int N = nums.length;

        // 1. Calculate total XOR sum S
        long totalXorSum = 0;
        for (long num : nums) {
            totalXorSum ^= num;
        }

        // 2. Calculate the required XOR sum T' for the removed set D
        // XOR_SUM(R) = target
        // XOR_SUM(D) = totalXorSum XOR target
        long requiredXorSumD = totalXorSum ^ target;

        // 3. Split nums into A and B (Meet-in-the-Middle)
        int N_A = N / 2;
        long[] A = new long[N_A];
        long[] B = new long[N - N_A];

        for (int i = 0; i < N_A; i++) {
            A[i] = nums[i];
        }
        for (int i = 0; i < N - N_A; i++) {
            B[i] = nums[N_A + i];
        }

        // 4. Generate maps for A and B
        Map<Long, Integer> mapA = generateXorSumMap(A);
        Map<Long, Integer> mapB = generateXorSumMap(B);

        // 5. Find the minimum total size |D| = |D_A| + |D_B|
        int minRemovedSize = N + 1;

        boolean found = false;

        // Iterate through results from mapA
        for (Map.Entry<Long, Integer> entryA : mapA.entrySet()) {
            long xA = entryA.getKey();
            int sA = entryA.getValue();

            // Required XOR sum from B: xB = T' XOR xA
            long xB_required = requiredXorSumD ^ xA;

            if (mapB.containsKey(xB_required)) {
                int sB = mapB.get(xB_required);
                int currentTotalSize = sA + sB;

                if (currentTotalSize < minRemovedSize) {
                    minRemovedSize = currentTotalSize;
                    found = true;
                }
            }
        }

        // 6. Return result
        if (found) {
            return minRemovedSize;
        } else {
            return -1;
        }
    }
}

