        Map<Long, Integer> map = new HashMap<>();
        int length = end - start;

        // Iterate through all 2^length subsets using bitmasks
        for (int i = 0; i < (1 << length); i++) {
            long currentXor = 0;
            int currentSize = 0;

            for (int j = 0; j < length; j++) {
