                    currentXor ^= nums[start + j];
                    currentSize++;
                }
            }

            // Update the map: keep the maximum size for this XOR sum
            map.put(currentXor, Math.max(map.getOrDefault(currentXor, -1), currentSize));
        }
        return map;
    }

