        int N = nums.length;
        if (N == 0) {
            return target == 0 ? 0 : -1;
        }

        int N_A = N / 2;

        // 1. Generate map for the first half [0, N_A - 1]
        Map<Long, Integer> mapA = generateMap(nums, 0, N_A);

        // 2. Generate map for the second half [N_A, N - 1]
        Map<Long, Integer> mapB = generateMap(nums, N_A, N);

        // 3. Find the maximum total size of a subset whose XOR sum equals target
        int maxSize = -1;

        for (Map.Entry<Long, Integer> entryA : mapA.entrySet()) {
            long xorA = entryA.getKey();
            int sizeA = entryA.getValue();

